    UITabBarController *tabBarController = (UITabBarController *)rootVC;
    UIViewController *selectedVC = tabBarController.selectedViewController;
    UINavigationController *currentNavController = nil;
    if ([selectedVC isKindOfClass:[UINavigationController class]]) {
        currentNavController = (UINavigationController *)selectedVC;
    } else if (selectedVC.navigationController) {
        currentNavController = selectedVC.navigationController;
    }
    for (UIViewController *vc in currentNavController.viewControllers) {
        if ([vc isKindOfClass:[WBFeedbackViewController class]]) {
            return YES;
        }
    }

    return NO;
}

