- (void)handleUniversalLink:(NSURL *)url {
    NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:YES];
    NSArray *queryItems = components.queryItems;

    NSMutableDictionary *params = [NSMutableDictionary dictionary];
    for (NSURLQueryItem *item in queryItems) {
        if (item.value) {
            [params setObject:item.value forKey:item.name];
        }
    }

    NSString *vappBundleId = params[@"vappBundleId"];
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];

    if ([rootVC isKindOfClass:[WBMainViewController class]]) {  // 前台、后台存活
        if(vappBundleId){
            [WBAppManager sharedManager].entryMethod = WBAppEntryMethodUniversalLink;
            [WBGroMoreAdManager sharedManager].vappMsgTapInAdClose = TRUE;
            [WBHomeViewController msgTappedCheckAndLaunchVApp:vappBundleId];
        }
        //        [action executeWithDefaultHandler:nil];
    } else { // Token hasn't yet been requested or is not on B page.    // 后台被杀，点击通知启动
        if(vappBundleId) {
            [WBAppManager sharedManager].entryMethod = WBAppEntryMethodUniversalLink;
            [WBGroMoreAdManager sharedManager].vappMsgTapInAdClose = TRUE;
            [WBAppManager sharedManager].vappBundleId = vappBundleId;
        }

        // 模拟 NSNotification 对象
        NSDictionary *userInfo = @{
            @"Type": @"simulation",
        };
        NSNotification *mockNotification = [NSNotification notificationWithName:@"WBSimulationNotification"
                                                                         object:nil
                                                                       userInfo:userInfo];
        WBBaseActionModel *action = [self buildActionWithNotification:mockNotification];
        [WBAppManager sharedManager].stashedAction = action;
    }
}

