- (void)handleShortcutItem:(UIApplicationShortcutItem *)shortcutItem {
    NSString *contactSupport = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".contactSupport"];
    NSString *modifySettings = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".modifySettings"];
    if ([shortcutItem.type isEqualToString:contactSupport] && ![self isFeedbackViewControllerAlreadyPresented]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (!self.window) return;

            UIViewController *rootVC = self.window.rootViewController;

            // 检查并关闭当前展示的模态界面
            [self dismissPresentedModalViewControllersFromViewController:rootVC completion:^{
                // 模态界面关闭后，再继续处理客服界面的展示
                UINavigationController *targetNavController = nil;
                UITabBarController *tabBarController = (UITabBarController *)rootVC;
                UIViewController *selectedVC = tabBarController.selectedViewController;
                if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                    targetNavController = (UINavigationController *)selectedVC;
                } else if (selectedVC.navigationController) {
                    targetNavController = selectedVC.navigationController;
                }

                if (targetNavController) {
                    WBFeedbackViewController *feedbackVC = [[WBFeedbackViewController alloc] init];
                    [targetNavController pushViewController:feedbackVC animated:YES];
                }
            }];
        });
    } else if ([shortcutItem.type isEqualToString:modifySettings]
               && ![self isSettingViewControllerAlreadyPresented]
               && !WBSettingManager.sharedManager.IsPretending) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (!self.window) return;

            UIViewController *rootVC = self.window.rootViewController;

            // 检查并关闭当前展示的模态界面
            [self dismissPresentedModalViewControllersFromViewController:rootVC completion:^{
                // 模态界面关闭后，再继续处理设置界面的展示
                UINavigationController *targetNavController = nil;
                UITabBarController *tabBarController = (UITabBarController *)rootVC;
                UIViewController *selectedVC = tabBarController.selectedViewController;
                if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                    targetNavController = (UINavigationController *)selectedVC;
                } else if (selectedVC.navigationController) {
                    targetNavController = selectedVC.navigationController;
                }

                if (targetNavController) {
                    WBSettingGlobalViewController *SettingVC = [[WBSettingGlobalViewController alloc] init];
                    [targetNavController pushViewController:SettingVC animated:YES];
                }
            }];
        });
    }
}

// 递归关闭所有模态展示的视图控制器
- (void)dismissPresentedModalViewControllersFromViewController:(UIViewController *)viewController completion:(void (^)(void))completion {
    UIViewController *presentedViewController = viewController.presentedViewController;

    if (presentedViewController) {
        [self dismissPresentedModalViewControllersFromViewController:presentedViewController completion:^{
            [presentedViewController dismissViewControllerAnimated:NO completion:completion];
        }];
    } else {
        // 没有更多模态视图，直接执行完成回调
        if (completion) {
            completion();
        }
    }
}

// 检查是否已经展示了客服界面
- (BOOL)isFeedbackViewControllerAlreadyPresented {
    if (!self.window) return NO;

    UIViewController *rootVC = self.window.rootViewController;
    UITabBarController *tabBarController = (UITabBarController *)rootVC;
    UIViewController *selectedVC = tabBarController.selectedViewController;
    UINavigationController *currentNavController = nil;
    if ([selectedVC isKindOfClass:[UINavigationController class]]) {
        currentNavController = (UINavigationController *)selectedVC;
    } else if (selectedVC.navigationController) {
        currentNavController = selectedVC.navigationController;
    }
    for (UIViewController *vc in currentNavController.viewControllers) {
        if ([vc isKindOfClass:[WBFeedbackViewController class]]) {
            return YES;
        }
    }

    return NO;
}

- (BOOL)isSettingViewControllerAlreadyPresented {
    if (!self.window) return NO;

