- (void)jun_routeBuild:(JUNRouteBuilder *)route {
    [route name:@"vip" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *triggerId = (id)userInfo[@"triggerId"] == [NSNull null] ? nil : userInfo[@"triggerId"];
        NSString *source = (id)userInfo[@"source"] == [NSNull null] ? nil : userInfo[@"source"];
        if (source) {
            [self presentVipPagePrivateFromPageSource:source triggerId:triggerId];
        } else {
            [self presentVipPagePrivateFromPageSource:@"link" triggerId:triggerId];
        }
    }];

    [route name:@"login" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *method = userInfo[@"method"];
        WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
        if (method.length == 0 || [method isEqualToString:@"phonenum"]) {
            loginVC.loginMethod = WBLoginMethodPhoneNumber;
        } else if ([method isEqualToString:@"password"]) {
            loginVC.loginMethod = WBLoginMethodPassword;
        } else {
            NSAssert(false, @"method invalid");
        }
        UINavigationController *loginNav = [[UINavigationController alloc] initWithRootViewController:loginVC];
        loginNav.modalPresentationStyle = UIModalPresentationFullScreen;
        [(self.presentedViewController ?: self) presentViewController:loginNav animated:YES completion:^{
            next(loginVC);
        }];
    }];
}

